    best = float('inf')
    for c1 in range(3):
        for c2 in range(3):
            c3 = 0
            valid = True
            for x in a:
                remaining = x - c1 * 1 - c2 * 2
                if remaining < 0:
                    need3 = 0
                else:
                    need3 = math.ceil(remaining / 3)
                c3 = max(c3, need3)
            total = c1 + c2 + c3
            best = min(best, total)

